#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <sys/time.h>
#include <omp.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_cpu(	par_str par_cpu,
					dim_str dim_cpu,
					box_str* box_cpu,
					FOUR_VECTOR* rv_cpu,
					fp* qv_cpu,
					FOUR_VECTOR* fv_cpu)
{
	long number_boxes = dim_cpu.number_boxes;
	fp alpha = par_cpu.alpha;
	fp a2 = 2.0 * alpha * alpha;

	#pragma omp parallel
	{
		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		#pragma omp for
		for (int bx = 0; bx < number_boxes; bx++) {
			int first_i = box_cpu[bx].offset;
			int nn = box_cpu[bx].nn;

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rA_shared[wtx] = rv_cpu[first_i + wtx];
			}

			for (int k = 0; k <= nn; k++) {
				int pointer;
				if (k == 0) {
					pointer = bx;
				} else {
					pointer = box_cpu[bx].nei[k-1].number;
				}

				int first_j = box_cpu[pointer].offset;

				for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
					rB_shared[wtx] = rv_cpu[first_j + wtx];
					qB_shared[wtx] = qv_cpu[first_j + wtx];
				}

				for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
					FOUR_VECTOR rA = rA_shared[wtx];
					fp fx_total = 0.0;
					fp fy_total = 0.0;
					fp fz_total = 0.0;
					fp v_total = 0.0;

					for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
						FOUR_VECTOR rB = rB_shared[j];
						fp qB = qB_shared[j];

						fp r2 = rA.v + rB.v - DOT(rA, rB);
						fp u2 = a2 * r2;
						fp vij = exp(-u2);
						fp fs = 2.0 * vij;

						fp dx = rA.x - rB.x;
						fp dy = rA.y - rB.y;
						fp dz = rA.z - rB.z;

						fp fxij = fs * dx;
						fp fyij = fs * dy;
						fp fzij = fs * dz;

						v_total += qB * vij;
						fx_total += qB * fxij;
						fy_total += qB * fyij;
						fz_total += qB * fzij;
					}

					fv_cpu[first_i + wtx].v += v_total;
					fv_cpu[first_i + wtx].x += fx_total;
					fv_cpu[first_i + wtx].y += fy_total;
					fv_cpu[first_i + wtx].z += fz_total;
				}
			}
		}
	}
}

#ifdef __cplusplus
}
#endif
